@namespace Lumeo

<CascadingValue Value="_context" IsFixed="false">
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Raised when a card is dropped onto a column (mouse/touch drag) and the
    /// board can resolve which card moved, from which column, to which column
    /// and at what index. Fires only when cards carry a <c>CardId</c> and
    /// columns a <c>ColumnId</c>; otherwise the per-column <c>OnDrop</c> still
    /// fires with the raw event for fully-manual boards.
    /// </summary>
    [Parameter] public EventCallback<DropEventArgs> OnCardDrop { get; set; }

    /// <summary>
    /// Raised when a card is moved via the keyboard (arrow keys on a focused
    /// card): Left/Right move it to the previous/next column, Up/Down reorder
    /// it within its column. Provides the keyboard-accessible alternative to
    /// drag-and-drop. Requires <c>CardId</c> on cards and <c>ColumnId</c> on
    /// columns so the board can resolve the move.
    /// </summary>
    [Parameter] public EventCallback<MoveEventArgs> OnCardMove { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex gap-4 overflow-x-auto p-4", Class);

    private BoardContext _context = default!;

    protected override void OnInitialized() => _context = new BoardContext(this);

    internal Task NotifyCardDrop(DropEventArgs args) => OnCardDrop.InvokeAsync(args);
    internal Task NotifyCardMove(MoveEventArgs args) => OnCardMove.InvokeAsync(args);

    /// <summary>The direction of a keyboard-initiated card move.</summary>
    public enum MoveDirection { Left, Right, Up, Down }

    /// <summary>Payload describing a drag-drop of a card between/within columns.</summary>
    public sealed record DropEventArgs(string CardId, string? FromColumnId, string ToColumnId, int ToIndex);

    /// <summary>Payload describing a keyboard-initiated card move.</summary>
    public sealed record MoveEventArgs(string CardId, string FromColumnId, MoveDirection Direction);

    /// <summary>
    /// A single stable instance cascaded per board. Tracks the in-flight drag so a
    /// column's drop handler can read which card is being dragged and from where —
    /// the HTML5 DataTransfer is unreliable (and empty under the touch shim), so the
    /// board carries the drag identity itself.
    /// </summary>
    public sealed record BoardContext
    {
        private readonly Kanban _board;
        public BoardContext(Kanban board) => _board = board;

        public string? DraggingCardId { get; private set; }
        public string? DraggingFromColumnId { get; private set; }

        // The STABLE consumer CardId of a card that just moved via the keyboard
        // and must be re-focused after the consumer re-renders the board. A
        // keyboard move re-creates the moved card's element (it lands in a new
        // column / slot), which drops focus to <body> and breaks chained arrow
        // moves. Keying by CardId (which travels with the data) — rather than the
        // per-instance generated element id — means the correct card re-focuses
        // even when consumers render cards WITHOUT @key, where Blazor reuses
        // component instances positionally and the old element id would otherwise
        // belong to whichever card shifted into the moved card's old slot. The
        // owning card claims this id on its next render and restores focus once.
        public string? PendingFocusCardId { get; private set; }

        public bool HasCardDropHandler => _board.OnCardDrop.HasDelegate;
        public bool HasCardMoveHandler => _board.OnCardMove.HasDelegate;

        /// <summary>Records the stable consumer CardId to re-focus after a keyboard move.</summary>
        public void RequestFocusAfterMove(string cardId) => PendingFocusCardId = cardId;

        /// <summary>Returns and clears the pending re-focus request when it matches this
        /// card's stable CardId, so exactly one card re-focuses exactly once.</summary>
        public bool TryConsumeFocusRequest(string cardId)
        {
            if (PendingFocusCardId != cardId) return false;
            PendingFocusCardId = null;
            return true;
        }

        public void BeginDrag(string cardId, string? fromColumnId)
        {
            DraggingCardId = cardId;
            DraggingFromColumnId = fromColumnId;
        }

        public void EndDrag()
        {
            DraggingCardId = null;
            DraggingFromColumnId = null;
        }

        public Task NotifyDrop(DropEventArgs args) => _board.NotifyCardDrop(args);
        public Task NotifyMove(MoveEventArgs args) => _board.NotifyCardMove(args);
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.IComponentInteropService Interop

<div class="@CssClass"
     id="@_cardId"
     draggable="@(Draggable ? "true" : "false")"
     role="@(IsInteractive ? "button" : null)"
     tabindex="@(IsInteractive ? "0" : null)"
     aria-roledescription="@(KeyboardMovable ? L["Kanban.CardRoleDescription"] : null)"
     @ondragstart="HandleDragStart"
     @ondragend="HandleDragEnd"
     @ondragover="HandleDragOver"
     @onclick="OnClick"
     @onkeydown="HandleKeyDown"
     @attributes="AdditionalAttributes">

    @if (Labels is not null && Labels.Count > 0)
    {
        <div class="flex flex-wrap gap-1 mb-2">
            @foreach (var label in Labels)
            {
                <span class="@GetLabelClass(label.Color) inline-flex items-center px-1.5 py-0.5 rounded text-xs font-medium">
                    @label.Text
                </span>
            }
        </div>
    }

    @if (ChildContent is not null)
    {
        @ChildContent
    }
    else
    {
        <p class="text-sm font-medium leading-snug">@Title</p>
        @if (!string.IsNullOrEmpty(Description))
        {
            <p class="mt-1 text-xs text-muted-foreground line-clamp-2">@Description</p>
        }
    }

    @if (!string.IsNullOrEmpty(Avatar))
    {
        <div class="mt-2 flex justify-end">
            <img src="@Avatar" alt="Assignee" class="w-6 h-6 rounded-full object-cover border border-border/40" />
        </div>
    }
</div>

@code {
    [CascadingParameter] private Kanban.BoardContext? Board { get; set; }
    [CascadingParameter] private KanbanColumn.ColumnContext? Column { get; set; }

    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Description { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public List<KanbanLabel>? Labels { get; set; }
    [Parameter] public string? Avatar { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Draggable { get; set; } = true;

    /// <summary>Stable id for this card, written into the board's drop/move payloads.</summary>
    [Parameter] public string? CardId { get; set; }

    /// <summary>This card's position within its column. Optional: when left unset
    /// the column derives the insert index from the card's sibling order at drop
    /// time, so the documented usage (which omits Index) still produces a precise
    /// insert index instead of always targeting position 0.</summary>
    [Parameter] public int Index { get; set; } = -1;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("bg-card rounded-lg border border-border/40 p-3 shadow-sm cursor-pointer hover:shadow-md transition-shadow focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2", Class);

    private readonly string _cardId = LumeoIds.New("kanban-card");

    // The card joins the board's keyboard-move flow when it has an id and the
    // board exposes a move handler. It is interactive (focusable) when it can be
    // clicked OR keyboard-moved.
    private bool KeyboardMovable => CardId is { Length: > 0 } && Board is { HasCardMoveHandler: true };
    private bool IsInteractive => OnClick.HasDelegate || KeyboardMovable;

    // When keyboard-movable, suppress the browser default (page/column scroll)
    // for the arrow keys so they reorder/move the card instead. Registered
    // against the id the DOM actually carries (a consumer id in the splat wins
    // over the generated one); re-registered when that id or movability changes.
    private string? _pdRegisteredId;

    // Register with the column on first render so the column can derive this
    // card's insert index from its sibling order (the consumer-supplied Index is
    // optional and the documented usage omits it).
    private KanbanColumn.ColumnContext? _registeredColumn;

    protected override void OnParametersSet()
    {
        if (!ReferenceEquals(_registeredColumn, Column))
        {
            _registeredColumn?.UnregisterCard(this);
            Column?.RegisterCard(this);
            _registeredColumn = Column;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        var targetId = KeyboardMovable ? LumeoIds.Effective(AdditionalAttributes, _cardId) : null;

        // Re-focus this card after a keyboard move re-rendered the board, so arrow
        // moves chain instead of dropping focus to <body>. Claimed (and cleared)
        // exactly once by the card whose STABLE CardId matches the board's request,
        // then focused via THIS instance's live element id. Keying the claim by
        // CardId (not the element id) keeps the right card focused when consumers
        // render without @key — Blazor then reuses instances positionally, so the
        // element id alone would re-focus the card that slid into the moved card's
        // old slot rather than the one the user moved.
        if (targetId is not null && CardId is { Length: > 0 } cardId
            && Board is { } board && board.TryConsumeFocusRequest(cardId))
        {
            try { await Interop.FocusElement(targetId); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }

        if (_pdRegisteredId == targetId) return;
        try
        {
            if (_pdRegisteredId is not null)
                await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId);
            if (targetId is not null)
                await Interop.RegisterPreventDefaultKeys(targetId, new[]
                {
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowLeft", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowRight", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowUp", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowDown", SkipEditable: true),
                });
            _pdRegisteredId = targetId;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private void HandleDragStart()
    {
        // Record the drag identity on the board so the destination column can
        // emit an enriched drop payload (DataTransfer is unreliable / empty
        // under the touch shim). A consumer-supplied @ondragstart splatted via
        // AdditionalAttributes still runs and wins, keeping manual boards working.
        if (CardId is { Length: > 0 } id && Board is { } board)
            board.BeginDrag(id, Column?.ColumnId);
    }

    private void HandleDragEnd()
    {
        Board?.EndDrag();
    }

    private void HandleDragOver()
    {
        // Advertise this card's slot as the insert target while hovered. Prefer the
        // card's actual sibling position (derived by the column from its child order)
        // over a consumer-supplied Index, which the documented usage omits — relying
        // on the default would advertise 0 for every card and break the insert index.
        Column?.SetPendingIndexFor(this, Index);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (KeyboardMovable && Column?.ColumnId is { } fromColumn)
        {
            var dir = e.Key switch
            {
                "ArrowLeft" => (Kanban.MoveDirection?)Kanban.MoveDirection.Left,
                "ArrowRight" => Kanban.MoveDirection.Right,
                "ArrowUp" => Kanban.MoveDirection.Up,
                "ArrowDown" => Kanban.MoveDirection.Down,
                _ => null
            };
            if (dir is { } d && Board is { } board)
            {
                // Ask the board to restore focus to this card after the consumer
                // re-renders the move — the moved element is re-created and would
                // otherwise drop focus to <body>, breaking chained arrow moves.
                // Key the request by the STABLE CardId (which travels with the
                // data), not the per-instance generated element id: without
                // @key on the cards, Blazor reuses component instances by
                // position, so the old element id would re-focus whichever card
                // shifted into the moved card's old slot instead of the card the
                // user actually moved.
                board.RequestFocusAfterMove(CardId!);
                await board.NotifyMove(new Kanban.MoveEventArgs(CardId!, fromColumn, d));
                return;
            }
        }

        if (OnClick.HasDelegate && e.Key is "Enter" or " ")
            await OnClick.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        _registeredColumn?.UnregisterCard(this);
        _registeredColumn = null;
        if (_pdRegisteredId is null) return;
        try { await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private static string GetLabelClass(string color) => color switch
    {
        "primary" => "bg-primary/10 text-primary",
        "destructive" => "bg-destructive/10 text-destructive",
        "warning" => "bg-warning-light text-warning-text",
        "success" => "bg-success-light text-success-text",
        "secondary" => "bg-secondary text-secondary-foreground",
        _ => "bg-muted text-muted-foreground"
    };

    public class KanbanLabel
    {
        public string Text { get; set; } = "";
        public string Color { get; set; } = "primary";
    }
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<CascadingValue Value="_columnContext" IsFixed="false">
    <div class="@CssClass" @attributes="AdditionalAttributes">
        <div class="flex items-center justify-between px-3 py-2 border-b border-border/40">
            @if (HeaderContent is not null)
            {
                @HeaderContent
            }
            else
            {
                <div class="flex items-center gap-2">
                    <span class="font-medium text-sm">@Title</span>
                    @if (Badge.HasValue)
                    {
                        <span class="inline-flex items-center justify-center min-w-5 h-5 px-1.5 rounded-[calc(var(--radius)*2)] bg-muted text-muted-foreground text-xs font-medium">
                            @Badge.Value
                        </span>
                    }
                </div>
            }
        </div>

        <div class="flex-1 overflow-y-auto p-2 flex flex-col gap-2 min-h-16"
             @ondragover:preventDefault
             @ondragenter="OnColumnDragEnter"
             @ondrop="HandleDrop">
            @ChildContent
        </div>

        @if (AllowAdd)
        {
            <div class="p-2 border-t border-border/40">
                <button type="button"
                        class="w-full flex items-center gap-2 px-3 py-2 rounded-md text-sm text-muted-foreground hover:bg-muted/50 hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                        @onclick="OnAdd">
                    <SvgGlyph Svg="@(LumeoIcons.Plus)" class="h-3.5 w-3.5" />
                    @L["Kanban.AddCard"]
                </button>
            </div>
        }
    </div>
</CascadingValue>

@code {
    [CascadingParameter] private Kanban.BoardContext? Board { get; set; }

    [Parameter] public string? Title { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int? Badge { get; set; }
    [Parameter] public RenderFragment? HeaderContent { get; set; }
    [Parameter] public bool AllowAdd { get; set; }
    [Parameter] public EventCallback OnAdd { get; set; }

    /// <summary>
    /// Raw drop event. Still fired for fully-manual boards that track drag state
    /// themselves. For an enriched payload (which card, from/to column, index)
    /// give the column a <c>ColumnId</c>, give cards a <c>CardId</c>, and handle
    /// <c>Kanban.OnCardDrop</c> at the board level.
    /// </summary>
    [Parameter] public EventCallback<DragEventArgs> OnDrop { get; set; }

    /// <summary>Stable id for this column, written into the board's drop/move payloads.</summary>
    [Parameter] public string? ColumnId { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex flex-col w-72 shrink-0 rounded-lg bg-muted/30 border border-border/40 max-h-full", Class);

    private ColumnContext _columnContext = default!;

    // The insert index a hovered card last advertised; -1 means "append" (drop
    // landed on the column body, not on a specific card).
    private int _pendingIndex = -1;

    // Child cards register themselves (in mount/declaration order) so the column
    // can derive a hovered card's insert index from its sibling position. This
    // makes the drop index correct even when the consumer omits KanbanCard.Index
    // (the documented usage does), where every card would otherwise advertise 0.
    private readonly List<KanbanCard> _cards = new();

    protected override void OnInitialized() => _columnContext = new ColumnContext(this);

    private void RegisterCard(KanbanCard card)
    {
        if (!_cards.Contains(card))
            _cards.Add(card);
    }

    private void UnregisterCard(KanbanCard card) => _cards.Remove(card);

    // Resolve a card's insert index: prefer the column-derived sibling position;
    // fall back to a consumer-supplied explicit Index (>= 0), then to append (-1).
    private void SetHoveredCard(KanbanCard card, int explicitIndex)
    {
        var derived = _cards.IndexOf(card);
        _pendingIndex = derived >= 0 ? derived
            : explicitIndex >= 0 ? explicitIndex
            : -1;
    }

    private async Task HandleDrop(DragEventArgs e)
    {
        var board = Board;
        try
        {
            // Legacy raw-event path is always honored.
            await OnDrop.InvokeAsync(e);

            // Enriched path: only when we can resolve the dragged card + this column.
            if (board is not null && board.DraggingCardId is { } cardId && ColumnId is { } toColumn
                && board.HasCardDropHandler)
            {
                var toIndex = _pendingIndex < 0 ? int.MaxValue : _pendingIndex;
                await board.NotifyDrop(new Kanban.DropEventArgs(cardId, board.DraggingFromColumnId, toColumn, toIndex));
            }
        }
        finally
        {
            // Always clear drag state, even if a handler above threw, so the board
            // doesn't stay stuck mid-drag.
            _pendingIndex = -1;
            board?.EndDrag();
        }
    }

    // Hovering the column body (not a card) targets the end of the column.
    private void OnColumnDragEnter() => _pendingIndex = -1;

    /// <summary>Cascaded to child cards so a card can advertise the insert index
    /// when it is the drag-over target.</summary>
    public sealed record ColumnContext
    {
        private readonly KanbanColumn _column;
        public ColumnContext(KanbanColumn column) => _column = column;

        public string? ColumnId => _column.ColumnId;

        /// <summary>A card registers itself so the column can order its children.</summary>
        public void RegisterCard(KanbanCard card) => _column.RegisterCard(card);

        /// <summary>A card unregisters on dispose / when it moves columns.</summary>
        public void UnregisterCard(KanbanCard card) => _column.UnregisterCard(card);

        /// <summary>A card reports itself (and any explicit Index fallback) as the
        /// insert target when the pointer is over it; the column resolves the index
        /// from the card's sibling order.</summary>
        public void SetPendingIndexFor(KanbanCard card, int explicitIndex)
            => _column.SetHoveredCard(card, explicitIndex);
    }
}
